 1	import * as React from 'react';
 2	import { createWizardNodeState } from '@odf/core/components/utils';
 3	import { useNodesData } from '@odf/core/hooks';
 4	import { useListPageFilter } from '@openshift-console/dynamic-plugin-sdk';
 5	import { render, screen } from '@testing-library/react';
 6	import { BrowserRouter } from 'react-router-dom-v5-compat';
 7	import { createFakeNodesData } from '../../../../../jest/helpers';
 8	import { SelectNodesTable } from './select-nodes-table';
 9	
10	jest.mock('@odf/core/hooks', () => ({
11	  ...jest.requireActual('@odf/core/hooks'),
12	  useNodesData: jest.fn(),
13	}));
14	// Mock needed due to sdk @console/internal declarations.
15	jest.mock('@openshift-console/dynamic-plugin-sdk', () => ({
16	  ...jest.requireActual('@openshift-console/dynamic-plugin-sdk'),
17	  ListPageFilter: jest.fn(() => null),
18	  useListPageFilter: jest.fn(),
19	}));
20	const onRowSelected = jest.fn();
21	
22	const systemNamespace = 'openshift-storage';
23	const cpu = 12;
24	const memory = 32 * 1000 * 1000 * 1000;
25	const nodes = createFakeNodesData(3, cpu, memory);
26	const selectedNodes = createWizardNodeState(nodes);
27	(useNodesData as jest.Mock).mockReturnValue([nodes, true, null]);
28	(useListPageFilter as jest.Mock).mockReturnValue([nodes, nodes, jest.fn()]);
29	
30	describe('Select Nodes Table', () => {
31	  it('shows the table including the Select All checkbox', () => {
32	    render(
33	      <BrowserRouter>
34	        <SelectNodesTable
35	          nodes={selectedNodes}
36	          onRowSelected={onRowSelected}
37	          systemNamespace={systemNamespace}
38	        />
39	      </BrowserRouter>
40	    );
41	
42	    const selectAll = screen.getByRole('checkbox', {
43	      name: /select all rows/i,
44	    });
45	    expect(selectAll).toBeVisible();
46	
47	    const footer = screen.getByTestId('nodes-selected');
48	    expect(footer).toBeVisible();
49	  });
50	
51	  it('shows the table without the Select All checkbox', () => {
52	    render(
53	      <BrowserRouter>
54	        <SelectNodesTable
55	          nodes={selectedNodes}
56	          onRowSelected={onRowSelected}
57	          disableLabeledNodes={true}
58	          systemNamespace={systemNamespace}
59	        />
60	      </BrowserRouter>
61	    );
62	
63	    const selectAll = screen.queryByRole('checkbox', {
64	      name: /select all rows/i,
65	    });
66	    expect(selectAll).not.toBeInTheDocument();
67	  });
68	});

